import{_ as e,c as o,o as d,aN as a}from"./chunks/framework.DXgs1r1w.js";const g=JSON.parse('{"title":"HTTP 基本概念","description":"","frontmatter":{"date":"2024-09-05T14:00:00.000Z","title":"HTTP 基本概念","outline":"deep","lastUpdated":true,"footer":true,"permalink":"/pages/c2d4f6","categories":["Linux","计算机网络","HTTP"]},"headers":[],"relativePath":"Linux/计算机网络/HTTP/HTTP基本概念.md","filePath":"Linux/计算机网络/HTTP/HTTP基本概念.md","lastUpdated":1784195928000}'),r={name:"Linux/计算机网络/HTTP/HTTP基本概念.md"};function n(s,t,l,i,c,h){return d(),o("div",null,[...t[0]||(t[0]=[a(`<h1 id="http-基本概念" tabindex="-1">HTTP 基本概念 <a class="header-anchor" href="#http-基本概念" aria-label="Permalink to &quot;HTTP 基本概念&quot;">​</a></h1><h2 id="一、http-是什么" tabindex="-1">一、HTTP 是什么？ <a class="header-anchor" href="#一、http-是什么" aria-label="Permalink to &quot;一、HTTP 是什么？&quot;">​</a></h2><p><strong>HTTP（HyperText Transfer Protocol，超文本传输协议）</strong> 是工作在 <strong>TCP/IP 协议族</strong>之上的<strong>应用层协议</strong>，用于客户端（通常是浏览器）和服务器之间传输超文本（HTML、图片、视频、JSON 等）。</p><p>核心特征：</p><ul><li><strong>基于 TCP</strong>：HTTP/1.1 和 HTTP/2 都基于 TCP（HTTP/3 改为基于 UDP 的 QUIC）。</li><li><strong>请求-响应模型</strong>：客户端主动发起请求（Request），服务器返回响应（Response）。</li><li><strong>无状态（Stateless）</strong>：服务器不保存客户端的请求历史，每次请求相互独立。状态由 Cookie / Session / Token 等手段在应用层维持。</li><li><strong>无连接（早期）</strong>：HTTP/1.0 每次请求都要新建 TCP 连接；HTTP/1.1 默认开启 <code>Connection: keep-alive</code> 复用连接。</li></ul><p>版本演进：</p><table tabindex="0"><thead><tr><th>版本</th><th>关键特性</th></tr></thead><tbody><tr><td>HTTP/0.9</td><td>仅支持 GET，无头部，纯文本</td></tr><tr><td>HTTP/1.0</td><td>引入请求头/响应头、状态码</td></tr><tr><td>HTTP/1.1</td><td>持久连接、管道化、分块传输、Host 头（主流）</td></tr><tr><td>HTTP/2</td><td>二进制分帧、多路复用、头部压缩、服务器推送</td></tr><tr><td>HTTP/3</td><td>基于 QUIC（UDP），解决队头阻塞，连接迁移</td></tr></tbody></table><hr><h2 id="二、http-常见的状态码有哪些" tabindex="-1">二、HTTP 常见的状态码有哪些？ <a class="header-anchor" href="#二、http-常见的状态码有哪些" aria-label="Permalink to &quot;二、HTTP 常见的状态码有哪些？&quot;">​</a></h2><p>状态码由 3 位数字组成，第一位表示类别：</p><h3 id="_1xx-信息性-—-请求已接收-继续处理" tabindex="-1">1xx（信息性）— 请求已接收，继续处理 <a class="header-anchor" href="#_1xx-信息性-—-请求已接收-继续处理" aria-label="Permalink to &quot;1xx（信息性）— 请求已接收，继续处理&quot;">​</a></h3><ul><li><strong>100 Continue</strong>：客户端可继续发送请求体。</li><li><strong>101 Switching Protocols</strong>：协议切换（如升级到 WebSocket）。</li></ul><h3 id="_2xx-成功-—-请求已成功处理" tabindex="-1">2xx（成功）— 请求已成功处理 <a class="header-anchor" href="#_2xx-成功-—-请求已成功处理" aria-label="Permalink to &quot;2xx（成功）— 请求已成功处理&quot;">​</a></h3><ul><li><strong>200 OK</strong>：请求成功，返回数据。</li><li><strong>201 Created</strong>：资源已创建（常见于 POST 新建）。</li><li><strong>202 Accepted</strong>：请求已接受但尚未处理完。</li><li><strong>204 No Content</strong>：成功但无返回体（如 DELETE）。</li><li><strong>206 Partial Content</strong>：范围请求成功（断点续传）。</li></ul><h3 id="_3xx-重定向-—-需要进一步操作" tabindex="-1">3xx（重定向）— 需要进一步操作 <a class="header-anchor" href="#_3xx-重定向-—-需要进一步操作" aria-label="Permalink to &quot;3xx（重定向）— 需要进一步操作&quot;">​</a></h3><ul><li><strong>301 Moved Permanently</strong>：永久重定向（SEO 权重转移）。</li><li><strong>302 Found</strong>：临时重定向。</li><li><strong>303 See Other</strong>：重定向到另一个资源（应使用 GET）。</li><li><strong>304 Not Modified</strong>：资源未修改，使用缓存（<strong>缓存核心状态码</strong>）。</li><li><strong>307 Temporary Redirect</strong>：临时重定向，方法和 body 不变。</li><li><strong>308 Permanent Redirect</strong>：永久重定向，方法和 body 不变。</li></ul><h3 id="_4xx-客户端错误-—-请求有问题" tabindex="-1">4xx（客户端错误）— 请求有问题 <a class="header-anchor" href="#_4xx-客户端错误-—-请求有问题" aria-label="Permalink to &quot;4xx（客户端错误）— 请求有问题&quot;">​</a></h3><ul><li><strong>400 Bad Request</strong>：请求语法错误。</li><li><strong>401 Unauthorized</strong>：未认证（需登录）。</li><li><strong>403 Forbidden</strong>：无权限访问（已认证但被拒绝）。</li><li><strong>404 Not Found</strong>：资源不存在。</li><li><strong>405 Method Not Allowed</strong>：请求方法不被允许。</li><li><strong>408 Request Timeout</strong>：请求超时。</li><li><strong>409 Conflict</strong>：请求与资源当前状态冲突。</li><li><strong>413 Payload Too Large</strong>：请求体过大。</li><li><strong>429 Too Many Requests</strong>：限流，请求过于频繁。</li></ul><h3 id="_5xx-服务器错误-—-服务器处理失败" tabindex="-1">5xx（服务器错误）— 服务器处理失败 <a class="header-anchor" href="#_5xx-服务器错误-—-服务器处理失败" aria-label="Permalink to &quot;5xx（服务器错误）— 服务器处理失败&quot;">​</a></h3><ul><li><strong>500 Internal Server Error</strong>：服务器内部错误。</li><li><strong>501 Not Implemented</strong>：功能未实现。</li><li><strong>502 Bad Gateway</strong>：网关/代理收到无效响应。</li><li><strong>503 Service Unavailable</strong>：服务不可用（过载或维护）。</li><li><strong>504 Gateway Timeout</strong>：网关超时。</li><li><strong>505 HTTP Version Not Supported</strong>：HTTP 版本不支持。</li></ul><blockquote><p>记忆口诀：<strong>1 信息、2 成功、3 重定向、4 客户端错、5 服务端错。</strong></p></blockquote><hr><h2 id="三、http-常见字段有哪些" tabindex="-1">三、HTTP 常见字段有哪些？ <a class="header-anchor" href="#三、http-常见字段有哪些" aria-label="Permalink to &quot;三、HTTP 常见字段有哪些？&quot;">​</a></h2><h3 id="通用字段-请求和响应都可用" tabindex="-1">通用字段（请求和响应都可用） <a class="header-anchor" href="#通用字段-请求和响应都可用" aria-label="Permalink to &quot;通用字段（请求和响应都可用）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>Cache-Control</code></td><td>缓存控制（如 <code>max-age=3600</code>、<code>no-cache</code>）</td></tr><tr><td><code>Connection</code></td><td>控制连接（如 <code>keep-alive</code>、<code>close</code>）</td></tr><tr><td><code>Date</code></td><td>报文创建时间</td></tr><tr><td><code>Transfer-Encoding</code></td><td>传输编码（如 <code>chunked</code> 分块）</td></tr><tr><td><code>Content-Type</code></td><td>实体媒体类型（如 <code>application/json</code>）</td></tr><tr><td><code>Content-Length</code></td><td>实体长度（字节）</td></tr></tbody></table><h3 id="请求字段-request-headers" tabindex="-1">请求字段（Request Headers） <a class="header-anchor" href="#请求字段-request-headers" aria-label="Permalink to &quot;请求字段（Request Headers）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>Host</code></td><td>目标主机名（HTTP/1.1 必需，用于虚拟主机）</td></tr><tr><td><code>User-Agent</code></td><td>客户端标识（浏览器/系统信息）</td></tr><tr><td><code>Accept</code></td><td>客户端可接受的响应类型</td></tr><tr><td><code>Accept-Encoding</code></td><td>可接受的压缩方式（gzip、br 等）</td></tr><tr><td><code>Accept-Language</code></td><td>可接受的语言</td></tr><tr><td><code>Authorization</code></td><td>认证凭据（如 Bearer Token）</td></tr><tr><td><code>Cookie</code></td><td>客户端携带的 Cookie</td></tr><tr><td><code>Referer</code></td><td>来源页面 URL</td></tr><tr><td><code>Range</code></td><td>请求部分内容（断点续传，<code>bytes=0-1023</code>）</td></tr><tr><td><code>Origin</code></td><td>跨域请求的源</td></tr></tbody></table><h3 id="响应字段-response-headers" tabindex="-1">响应字段（Response Headers） <a class="header-anchor" href="#响应字段-response-headers" aria-label="Permalink to &quot;响应字段（Response Headers）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>Server</code></td><td>服务器软件信息</td></tr><tr><td><code>Set-Cookie</code></td><td>服务器下发 Cookie</td></tr><tr><td><code>Location</code></td><td>重定向目标地址（配合 3xx）</td></tr><tr><td><code>ETag</code></td><td>资源版本标识（缓存校验）</td></tr><tr><td><code>Last-Modified</code></td><td>资源最后修改时间（缓存校验）</td></tr><tr><td><code>Expires</code></td><td>资源过期时间（绝对时间，HTTP/1.0）</td></tr><tr><td><code>Access-Control-Allow-Origin</code></td><td>跨域允许的来源</td></tr><tr><td><code>Content-Encoding</code></td><td>实际使用的压缩方式</td></tr><tr><td><code>WWW-Authenticate</code></td><td>认证挑战信息</td></tr></tbody></table><hr><h2 id="四、get-和-post-有什么区别" tabindex="-1">四、GET 和 POST 有什么区别？ <a class="header-anchor" href="#四、get-和-post-有什么区别" aria-label="Permalink to &quot;四、GET 和 POST 有什么区别？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比维度</th><th>GET</th><th>POST</th></tr></thead><tbody><tr><td><strong>语义</strong></td><td>获取资源（幂等、安全）</td><td>提交/创建资源（非幂等）</td></tr><tr><td><strong>参数位置</strong></td><td>拼在 URL 查询字符串中</td><td>放在请求体（body）中</td></tr><tr><td><strong>数据长度</strong></td><td>受 URL 长度限制（约 2KB~8KB，因浏览器而异）</td><td>理论上无限制</td></tr><tr><td><strong>安全性</strong></td><td>参数暴露在 URL、浏览器历史、日志中，不适合传敏感信息</td><td>数据在 body 中，相对不直接暴露（但<strong>仍需 HTTPS</strong> 才安全）</td></tr><tr><td><strong>缓存</strong></td><td>可被浏览器缓存、收藏为书签</td><td>一般不被缓存、不能收藏</td></tr><tr><td><strong>幂等性</strong></td><td>幂等（多次请求效果一致）</td><td>非幂等（多次提交可能产生副作用）</td></tr><tr><td><strong>回退/刷新</strong></td><td>无害，可重复</td><td>浏览器通常会弹窗确认重新提交</td></tr><tr><td><strong>编码类型</strong></td><td><code>application/x-www-form-urlencoded</code></td><td>支持 <code>multipart/form-data</code>（文件上传）等</td></tr></tbody></table><blockquote><p>注意：<strong>GET 和 POST 本质没有「安全」之分</strong>，HTTP 规范里 GET 仅是「语义上安全/幂等」，二者明文传输都需要 HTTPS 保护。所谓的「POST 比 GET 安全」是错误的，只是 POST 参数不在 URL 里。</p></blockquote><hr><h2 id="五、http-缓存有哪些实现方式" tabindex="-1">五、HTTP 缓存有哪些实现方式？ <a class="header-anchor" href="#五、http-缓存有哪些实现方式" aria-label="Permalink to &quot;五、HTTP 缓存有哪些实现方式？&quot;">​</a></h2><p>HTTP 缓存分为<strong>强缓存</strong>和<strong>协商缓存</strong>两大类。</p><h3 id="_1-强缓存-不发请求-直接用本地" tabindex="-1">1. 强缓存（不发请求，直接用本地） <a class="header-anchor" href="#_1-强缓存-不发请求-直接用本地" aria-label="Permalink to &quot;1. 强缓存（不发请求，直接用本地）&quot;">​</a></h3><p>命中时浏览器<strong>不发送请求</strong>到服务器，直接读本地缓存，状态码显示 <code>200 (from cache)</code>。</p><ul><li><strong><code>Expires</code></strong>（HTTP/1.0）：绝对过期时间，如 <code>Expires: Wed, 21 Oct 2026 07:00:00 GMT</code>。缺点：依赖客户端本地时间，可能有偏差。</li><li><strong><code>Cache-Control</code></strong>（HTTP/1.1，优先级更高）：相对时间，常用指令： <ul><li><code>max-age=3600</code>：缓存 3600 秒。</li><li><code>public</code>：可被任何缓存（含 CDN）缓存。</li><li><code>private</code>：仅客户端可缓存。</li><li><code>no-cache</code>：不直接用缓存，需经协商缓存验证。</li><li><code>no-store</code>：完全不缓存（敏感数据）。</li><li><code>must-revalidate</code>：过期后必须向服务器验证。</li></ul></li></ul><h3 id="_2-协商缓存-发请求-服务器判定是否用缓存" tabindex="-1">2. 协商缓存（发请求，服务器判定是否用缓存） <a class="header-anchor" href="#_2-协商缓存-发请求-服务器判定是否用缓存" aria-label="Permalink to &quot;2. 协商缓存（发请求，服务器判定是否用缓存）&quot;">​</a></h3><p>强缓存失效后，浏览器携带校验信息发请求，服务器返回 <code>304 Not Modified</code> 表示资源未变，浏览器用本地缓存。</p><ul><li><strong><code>Last-Modified</code> / <code>If-Modified-Since</code></strong>： <ul><li>响应头 <code>Last-Modified: &lt;时间&gt;</code> 记录资源最后修改时间。</li><li>再次请求时请求头带 <code>If-Modified-Since: &lt;时间&gt;</code>，服务器比对。</li><li>缺点：精度只到秒；内容没变但时间变了会误判；周期性生成内容会失效。</li></ul></li><li><strong><code>ETag</code> / <code>If-None-Match</code></strong>（更精准，优先级高于 Last-Modified）： <ul><li>响应头 <code>ETag: &quot;唯一标识&quot;</code>（通常是文件哈希或版本号）。</li><li>再次请求时请求头带 <code>If-None-Match: &quot;唯一标识&quot;</code>，服务器比对，相同则 <code>304</code>。</li></ul></li></ul><h3 id="_3-缓存决策流程" tabindex="-1">3. 缓存决策流程 <a class="header-anchor" href="#_3-缓存决策流程" aria-label="Permalink to &quot;3. 缓存决策流程&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请求资源</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>是否命中强缓存 (Cache-Control / Expires)?</span></span>
<span class="line"><span>   │ 是 ───► 200 (from cache)，直接用，不发请求</span></span>
<span class="line"><span>   │ 否</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>发请求，带 If-Modified-Since / If-None-Match</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>服务器比对 ── 资源未变 ──► 304 Not Modified，用本地缓存</span></span>
<span class="line"><span>            ── 资源已变 ──► 200 OK，返回新内容并更新缓存</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h3 id="_4-其他缓存手段" tabindex="-1">4. 其他缓存手段 <a class="header-anchor" href="#_4-其他缓存手段" aria-label="Permalink to &quot;4. 其他缓存手段&quot;">​</a></h3><ul><li><strong>Service Worker</strong>：在浏览器端拦截请求，可编程控制缓存（PWA 离线能力）。</li><li><strong>CDN 缓存</strong>：边缘节点缓存静态资源，就近返回。</li><li><strong>浏览器本地存储</strong>：<code>localStorage</code> / <code>sessionStorage</code>（非 HTTP 缓存，但常用于缓存接口数据）。</li><li><strong>HTML 的 <code>&lt;meta&gt;</code> 缓存</strong>（已不推荐，作用有限）。</li></ul><blockquote><p>实践建议：静态资源（JS/CSS/图片）用 <code>Cache-Control: max-age + 文件名哈希（内容变则文件名变）</code>；HTML 入口用 <code>no-cache</code> 保证及时更新；接口数据用 <code>ETag</code> 协商缓存。</p></blockquote>`,47)])])}const T=e(r,[["render",n]]);export{g as __pageData,T as default};
